// src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, LayersControl, useMapEvents } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import PinsLayer from "./PinsLayer";
import { PIN_TYPES } from "./pinsConfig";

// City -> coords
const CITY_CENTER = {
  "Atlanta, US": [33.749, -84.388],
  "New York, US": [40.7128, -74.006],
  "London, UK": [51.5074, -0.1278],
  "Dubai, AE": [25.2048, 55.2708],
};

// Click-to-add helper IN THIS FILE so it’s defined
function ClickToAdd({ enabled, type, onAdd }) {
  useMapEvents({
    click(e) {
      if (!enabled) return;
      onAdd?.({
        id: crypto.randomUUID(),
        lat: e.latlng.lat,
        lng: e.latlng.lng,
        type,
        timestamp: Date.now(),
      });
    },
  });
  return null;
}

export default function Radar({ city = "Atlanta, US", pins = [], onAddPin }) {
  const center = CITY_CENTER[city] ?? CITY_CENTER["Atlanta, US"];
  const [opacity, setOpacity] = useState(0.8);
  const [basemap, setBasemap] = useState("voyager");
  const [addMode, setAddMode] = useState(false);
  const [reportType, setReportType] = useState("rain");

  const baseTiles = useMemo(
    () => ({
      voyager: { url: "https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png", maxZoom: 18 },
      dark:    { url: "https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png", maxZoom: 18 },
      light:   { url: "https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png", maxZoom: 18 },
    }),
    []
  );

  const radarTileURL = "https://tilecache.rainviewer.com/v2/radar/now/256/{z}/{x}/{y}/2/1_1.png";
  const activeBase = baseTiles[basemap] || baseTiles.voyager;

  // optional: stop any timers if you add loop logic later
  const loopTimerRef = useRef(null);
  useEffect(() => () => { if (loopTimerRef.current) clearInterval(loopTimerRef.current); }, []);

  return (
    <div
      className="
        relative
        w-full
        h-[60vh] sm:h-[65vh]
        mt-auto
        rounded-2xl
        overflow-hidden
        shadow-lg
        bg-black/50 backdrop-blur-md
        border border-white/10
      "
    >
      <MapContainer
        center={center}
        zoom={8}
        minZoom={3}
        maxZoom={18}
        className="w-full h-full"
        zoomControl={false}
        attributionControl={false}
      >
        <LayersControl position="topright">
          <LayersControl.BaseLayer checked name="Basemap">
            <TileLayer url={activeBase.url} maxZoom={activeBase.maxZoom} />
          </LayersControl.BaseLayer>

          <LayersControl.Overlay checked name="Radar">
            <TileLayer url={radarTileURL} opacity={opacity} tileSize={256} zIndex={5} />
          </LayersControl.Overlay>

          <LayersControl.Overlay checked name="Community Pins">
            <PinsLayer pins={pins} />
          </LayersControl.Overlay>
        </LayersControl>

        <ClickToAdd enabled={addMode} type={reportType} onAdd={onAddPin} />
      </MapContainer>

      {/* Glass control panel */}
      <div className="absolute top-3 left-3 z-[1000] bg-black/60 backdrop-blur-md text-white rounded-xl p-3 flex flex-col gap-2 border border-white/10">
        <div className="flex items-center justify-between gap-3">
          <span className="text-sm">Opacity</span>
          <input
            type="range"
            min={0.2}
            max={1}
            step={0.05}
            value={opacity}
            onChange={(e) => setOpacity(parseFloat(e.target.value))}
            className="w-32 accent-purple-500"
          />
        </div>

        <div className="flex items-center justify-between gap-2">
          <span className="text-sm">Basemap</span>
          <select
            value={basemap}
            onChange={(e) => setBasemap(e.target.value)}
            className="bg-black/40 border border-white/10 rounded-lg px-2 py-1 text-sm"
          >
            <option value="voyager">Voyager</option>
            <option value="dark">Dark</option>
            <option value="light">Light</option>
          </select>
        </div>

        {/* Add report controls */}
        <div className="pt-1 border-t border-white/10">
          <div className="text-sm mb-1">Quick report</div>
          <div className="flex flex-wrap gap-1">
            {Object.entries(PIN_TYPES).map(([key, val]) => (
              <button
                key={key}
                onClick={() => setReportType(key)}
                className={`px-2 py-1 rounded-md text-xs border border-white/10 ${
                  reportType === key ? "bg-white/10 ring-1 ring-purple-400" : "bg-black/40 hover:bg-black/30"
                }`}
                title={val.label}
              >
                {val.emoji}
              </button>
            ))}
          </div>

          <button
            onClick={() => setAddMode((v) => !v)}
            className={`mt-2 w-full px-3 py-1.5 rounded-lg text-sm transition ${
              addMode ? "bg-purple-600 hover:bg-purple-500" : "bg-black/40 hover:bg-black/30 border border-white/10"
            }`}
          >
            {addMode ? "Click map to place (ON)" : "Add report pin"}
          </button>
        </div>
      </div>

      {/* Minimal attribution */}
      <div className="absolute bottom-2 right-3 z-[1000] text-[10px] text-white/80 bg-black/40 rounded px-2 py-1">
        Map © CARTO · Radar © RainViewer
      </div>
    </div>
  );
}
